import{_ as e,o as t,c as o,a2 as n}from"./chunks/framework.BWuWLRhz.js";const r="/autofac-run-map.svg",m=JSON.parse('{"title":"Autofac User Manual","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),s={name:"index.md"};function i(l,a,d,c,u,p){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="autofac-user-manual" tabindex="-1">Autofac User Manual <a class="header-anchor" href="#autofac-user-manual" aria-label="Permalink to &quot;Autofac User Manual&quot;">​</a></h1><p>Autofac is a governed software-delivery control plane for AI agents. It lets a team model delivery work as BPMN, assign steps to agents, gate tool use through policy, pause for human approvals, and keep an evidence trail for every run.</p><p>This site is the operator and developer manual for running Autofac, authoring workflows, configuring integrations, and extending the platform.</p><div class="doc-map"><img src="'+r+'" alt="Map of an Autofac run from trigger to BPMN run, agent task, policy gate, tool call, approval, and evidence."></div><h2 id="choose-your-path" tabindex="-1">Choose your path <a class="header-anchor" href="#choose-your-path" aria-label="Permalink to &quot;Choose your path&quot;">​</a></h2><div class="manual-grid"><a href="/start/quickstart.html"><strong>Start in five minutes</strong><span>Run the tokenless quickstart stack and complete the sample workflow.</span></a><a href="/manual/runs.html"><strong>Operate a run</strong><span>Start a workflow, inspect its BPMN state, and understand step outcomes.</span></a><a href="/manual/approvals-evidence.html"><strong>Approve and audit</strong><span>Handle human gates and download an evidence pack for the run.</span></a><a href="/admin/deployment.html"><strong>Deploy Autofac</strong><span>Move from quickstart to a hardened self-hosted deployment.</span></a><a href="/developer/local-development.html"><strong>Develop locally</strong><span>Build, test, and extend the .NET control plane and React UI.</span></a><a href="/reference/bpmn-extensions.html"><strong>Use the reference</strong><span>Look up BPMN extensions, policy boundaries, schema, and ADRs.</span></a></div><h2 id="what-you-can-do-with-autofac" tabindex="-1">What you can do with Autofac <a class="header-anchor" href="#what-you-can-do-with-autofac" aria-label="Permalink to &quot;What you can do with Autofac&quot;">​</a></h2><ul><li>Model SDLC workflows as versioned BPMN instead of prompt transcripts.</li><li>Run model-backed or deterministic agent tasks with bounded permissions.</li><li>Route every connector and tool call through the Tool Gateway.</li><li>Pause at human approval tasks, including high-risk policy decisions.</li><li>Run code-producing work inside Docker, OpenSandbox, or Kubernetes-backed sandboxes.</li><li>Export evidence packs that include prompts, redactions, policy decisions, tool invocations, approvals, model usage, artifacts, and audit records.</li><li>Keep the core platform self-hosted under your own data boundary.</li></ul><h2 id="before-production" tabindex="-1">Before production <a class="header-anchor" href="#before-production" aria-label="Permalink to &quot;Before production&quot;">​</a></h2><p>The quickstart is intentionally easy: it uses a deterministic mock model provider and development authentication defaults. Production deployments must configure real authentication, secret handling, storage, sandbox isolation, and observability. Start with <a href="/admin/deployment.html">Deployment</a>, then review <a href="/admin/settings-secrets.html">Settings And Secrets</a> and <a href="/admin/auth-data-residency.html">Auth And Data Residency</a>.</p>',10)])])}const f=e(s,[["render",i]]);export{m as __pageData,f as default};
